function solve(edges, online, k) {
    const n = online.length;
    const graph = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push({ node: v, cost });
    }

    // Use a max-heap to prioritize paths with higher minimum edge cost
    const maxHeap = new MaxHeap((a, b) => a.minCost - b.minCost);

    // Start from node 0
    maxHeap.push({ node: 0, minCost: Infinity, totalCost: 0 });

    while (!maxHeap.isEmpty()) {
