        // Traverse all neighbors
        if (graph.has(node)) {
            for (const { node: neighbor, cost } of graph.get(node)) {
                // Check if the neighbor is online
                if (!online[neighbor]) {
                    continue;
                }

                // Calculate the new total cost and new minimum edge cost
                const newTotalCost = totalCost + cost;
                const newMinCost = Math.min(minCost, cost);

                // If the total cost is within the limit, add to the heap
                if (newTotalCost <= k) {
                    maxHeap.push({ node: neighbor, minCost: newMinCost, totalCost: newTotalCost });
                }
            }
        }
    }

    // If no valid path is found
    return -1;
