func solve(edges [][]int64, online []bool, k int64) int64 {
    n := len(online)
    graph := make(map[int64][]struct {
        node int64
        cost int64
    })

    // Build the graph
    for _, edge := range edges {
        u, v, cost := edge[0], edge[1], edge[2]
        if _, exists := graph[u]; !exists {
            graph[u] = []struct {
                node int64
                cost int64
